import{_ as e,H as t,f as a,i as r}from"./chunks/framework.CKQqA5tu.js";const h=JSON.parse('{"title":"核心功能","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md"}'),i={name:"guide/features.md"};function l(n,o,s,d,c,u){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h1><p><code>unibestX</code> 内置了众多开箱即用的功能，旨在提升基于 uni-app X 的开发效率和体验。</p><h2 id="自定义-tabbar" tabindex="-1">自定义 TabBar <a class="header-anchor" href="#自定义-tabbar" aria-label="Permalink to &quot;自定义 TabBar&quot;">​</a></h2><p>项目内置了高度可定制的 TabBar 组件（位于 <code>src/tabbar</code>）：</p><ul><li><strong>多 Tab 支持</strong>：标准 5 个 Tab 项配置。</li><li><strong>特殊样式</strong>：支持中间凸起按钮（例如用于发布按钮或 AI 助手入口）。</li><li><strong>状态显示</strong>：支持角标显示（红点或数字）。</li><li><strong>主题化</strong>：全面支持动态主题色的响应。</li></ul><h2 id="路由守卫" tabindex="-1">路由守卫 <a class="header-anchor" href="#路由守卫" aria-label="Permalink to &quot;路由守卫&quot;">​</a></h2><p>提供了灵活且强大的页面访问控制：</p><ul><li><strong>黑名单模式</strong>（默认）：只有在配置中指定的页面才需要登录访问。</li><li><strong>白名单模式</strong>：除了指定的几个页面（如登录、注册、首页），其余全部页面都需要登录。</li><li><strong>智能跳转</strong>：支持拦截跳转登录，并在登录成功后自动跳回最初想访问的页面。</li></ul><h2 id="请求封装-http" tabindex="-1">请求封装 (HTTP) <a class="header-anchor" href="#请求封装-http" aria-label="Permalink to &quot;请求封装 (HTTP)&quot;">​</a></h2><p>基于 <code>lime-request</code> 封装的现代化 HTTP 客户端（位于 <code>src/http</code>）：</p><ul><li><strong>无感 Token</strong>：自动在请求头携带 Token，并支持 Token 自动续期。</li><li><strong>拦截器机制</strong>：全局请求与响应拦截，方便统一处理错误（如 401 自动登出）。</li><li><strong>多域名支持</strong>：轻松配置和切换不同的 API 域名环境。</li><li><strong>灵活配置</strong>：支持配置特定请求忽略认证。</li></ul><h2 id="状态管理与持久化" tabindex="-1">状态管理与持久化 <a class="header-anchor" href="#状态管理与持久化" aria-label="Permalink to &quot;状态管理与持久化&quot;">​</a></h2><p>基于 <code>x-pinia-s</code> (专为 uni-app X 优化的 Pinia)：</p><ul><li><strong>AppStore (<code>app.uts</code>)</strong>：管理应用的全局状态，如主题色、当前语言等。</li><li><strong>TokenStore (<code>token.uts</code>)</strong>：管理鉴权信息，内置支持单 Token 和双 Token (access + refresh) 模式。</li><li><strong>UserStore (<code>user.uts</code>)</strong>：管理登录用户的个人信息。</li><li><strong>自动持久化</strong>：内置持久化插件，状态改变时自动同步到本地设备存储中。</li></ul><h2 id="i18n-多语言支持" tabindex="-1">i18n 多语言支持 <a class="header-anchor" href="#i18n-多语言支持" aria-label="Permalink to &quot;i18n 多语言支持&quot;">​</a></h2><p>基于 <code>lime-i18n</code> 提供的国际化方案：</p><ul><li><strong>开箱即用</strong>：内置中文（<code>zh-CN</code>）和英文（<code>en-US</code>）基础语言包。</li><li><strong>系统感知</strong>：能够自动检测并跟随系统语言。</li><li><strong>生态兼容</strong>：支持 VSCode <code>i18n-ally</code> 插件，提升翻译编辑体验。</li><li><strong>全局可用</strong>：不仅能在 Vue 模板中使用，也支持在 <code>.uts</code> 脚本文件中调用翻译函数。</li></ul><h2 id="页面布局机制-layout" tabindex="-1">页面布局机制 (Layout) <a class="header-anchor" href="#页面布局机制-layout" aria-label="Permalink to &quot;页面布局机制 (Layout)&quot;">​</a></h2><p>借助自定义 Vite 插件 (<code>plugins/uni-layouts-plugin.ts</code>)，实现了灵活的页面布局：</p><ul><li><strong>自动注入</strong>：自动为页面包裹默认的 Layout 组件，无需在每个页面重复书写。</li><li><strong>自定义配置</strong>：支持在 <code>pages.json</code> 或页面顶部的 <code>&lt;route&gt;</code> 块中配置自定义使用的布局。</li><li><strong>按需禁用</strong>：可以通过设置 <code>layout: false</code> 单独为某个页面禁用布局包裹。</li></ul>',20)])])}const p=e(i,[["render",l]]);export{h as __pageData,p as default};
